func (qcc *QuicClient) Init() error {
	klog.Infof("Quic start to connect Access")
	cert, err := tls.LoadX509KeyPair(qcc.config.CertFilePath, qcc.config.KeyFilePath)
	if err != nil {
		klog.Errorf("Failed to load x509 key pair: %v", err)
		return fmt.Errorf("failed to load x509 key pair, error: %v", err)
	}
	caCrt, err := os.ReadFile(qcc.config.CaFilePath)
	if err != nil {
		klog.Errorf("Failed to load ca file: %s", err.Error())
		return fmt.Errorf("failed to load ca file: %s", err.Error())
	}
	pool := x509.NewCertPool()
	pool.AppendCertsFromPEM(caCrt)

	tlsConfig := &tls.Config{
		RootCAs:            pool,
		Certificates:       []tls.Certificate{cert},
		InsecureSkipVerify: true,
	}

	option := qclient.Options{
		HandshakeTimeout: qcc.config.HandshakeTimeout,
		TLSConfig:        tlsConfig,
		Type:             api.ProtocolTypeQuic,
		Addr:             qcc.config.Addr,
	}
	exOpts := api.QuicClientOption{Header: make(http.Header)}
	exOpts.Header.Set("node_id", qcc.config.NodeID)
	exOpts.Header.Set("project_id", qcc.config.ProjectID)
	client := qclient.NewQuicClient(option, exOpts)
	connection, err := client.Connect()
	if err != nil {
		klog.Errorf("Init quic connection failed %s", err.Error())
		return err
	}
	qcc.client = connection
	klog.Infof("Quic connect to cloud access successful")

	return nil
}

func (e *edgestream) Start() {
	serverURL := url.URL{
		Scheme: "wss",
		Host:   config.Config.TunnelServer,
		Path:   "/v1/kubeedge/connect",
	}
	// TODO: Will improve in the future
	if ok := <-edgehub.GetCertSyncChannel()[e.Name()]; !ok {
		klog.Exitf("Failed to find cert key pair")
	}

	cert, err := tls.LoadX509KeyPair(config.Config.TLSTunnelCertFile, config.Config.TLSTunnelPrivateKeyFile)
	if err != nil {
		klog.Exitf("Failed to load x509 key pair: %v", err)
	}
	tlsConfig := &tls.Config{
		InsecureSkipVerify: true,
		Certificates:       []tls.Certificate{cert},
	}

	ticker := time.NewTicker(time.Second * 2)
	defer ticker.Stop()

	for {
		select {
		case <-beehiveContext.Done():
			return
		case <-ticker.C:
			err := e.TLSClientConnect(serverURL, tlsConfig)
			if err != nil {
				klog.Errorf("TLSClientConnect error %v", err)
			}
		}
	}
}

func HubClientInit(server, clientID, username, password string) *MQTT.ClientOptions {
	opts := MQTT.NewClientOptions().AddBroker(server).SetClientID(clientID).SetCleanSession(true)
	if username != "" {
		opts.SetUsername(username)
		if password != "" {
			opts.SetPassword(password)
		}
	}

	klog.V(4).Infof("Start to set TLS configuration for MQTT client")
	tlsConfig := &tls.Config{}
	if eventconfig.Config.TLS.Enable {
		cert, err := tls.LoadX509KeyPair(eventconfig.Config.TLS.TLSMqttCertFile, eventconfig.Config.TLS.TLSMqttPrivateKeyFile)
		if err != nil {
			klog.Errorf("Failed to load x509 key pair: %v", err)
			return nil
		}

		caCert, err := os.ReadFile(eventconfig.Config.TLS.TLSMqttCAFile)
		if err != nil {
			klog.Errorf("Failed to read TLSMqttCAFile")
			return nil
		}

		pool := x509.NewCertPool()
		if ok := pool.AppendCertsFromPEM(caCert); !ok {
			klog.Errorf("Cannot parse the certificates")
			return nil
		}

		tlsConfig = &tls.Config{
			RootCAs:            pool,
			Certificates:       []tls.Certificate{cert},
			InsecureSkipVerify: false,
		}
	} else {
		tlsConfig = &tls.Config{InsecureSkipVerify: true, ClientAuth: tls.NoClientCert}
	}
	opts.SetTLSConfig(tlsConfig)
	klog.V(4).Infof("set TLS configuration for MQTT client successfully")

	return opts
}

